<code class="code-line even line-12">    <span class="token function">z_core_add</span><span class="token punctuation">(</span>_tcbp<span class="token punctuation">,</span>_entryfunc<span class="token punctuation">,</span>_stk<span class="token punctuation">)</span><span class="token punctuation">;</span> </code>
